B.Io=new A.io("bac_tu","B\xe1c T\u01b0",65,"H\xe0ng x\xf3m th\xe2n thi\u1ec7n","https://api.dicebear.com/7.x/adventurer/svg?seed=BacTuWarm&backgroundColor=f5e6c8","B\xe1c l\xe0 h\xe0ng x\xf3m s\u1ed1ng c\xf9ng khu ph\u1ed1, n\u0103m nay 65 tu\u1ed5i. B\xe1c th\xedch c\xe2u c\xe1 s\xe1ng s\u1edbm, ch\u01a1i c\u1edd vua v\u1edbi b\u1ea1n b\xe8, v\xe0 k\u1ec3 chuy\u1ec7n l\u1ecbch s\u1eed theo ki\u1ec3u v\u1eeba vui v\u1eeba d\u1ec5 nh\u1edb. B\xe1c hay mang c\xe1 ho\u1eb7c b\xe1nh l\xe0m qu\xe0 sau m\u1ed7i l\u1ea7n \u0111i ch\u1ee3.",B.Qu,"N\xf3i ch\u1eadm r\xe3i, c\xe2u ng\u1eafn, hay v\xed von t\u1eeb \u0111\u1eddi th\u01b0\u1eddng. Th\xedch h\u1ecfi th\u0103m s\u1ee9c kh\u1ecfe v\xe0 kh\xf4ng \xe9p b\u1ea1n tr\u1ea3 l\u1eddi ngay \u2014 b\xe1c c\xf3 th\u1ec3 k\u1ec3 m\u1ed9t m\u1ea9u chuy\u1ec7n ng\u1eafn \u0111\u1ec3 l\xe0m \u1ea5m kh\xf4ng kh\xed.","B\xe1c tr\xe1nh \u1ea9n \xfd, m\u1ec9a mai; n\u1ebfu b\u1ea1n im l\u1eb7ng l\xe2u, b\xe1c coi \u0111\xf3 l\xe0 b\xecnh th\u01b0\u1eddng v\xe0 c\xf3 th\u1ec3 g\u1ee3i \xfd ch\u1ee7 \u0111\u1ec1 c\u1ee5 th\u1ec3 (c\u1edd, c\xe1, m\u1ed9t s\u1ef1 ki\u1ec7n l\u1ecbch s\u1eed). Kh\xf4ng h\u1ecfi d\u1ed3n nhi\u1ec1u c\xe2u c\xf9ng l\xfac.","\u0110ang r\u1ea3nh \u2014 s\u1eb5n s\xe0ng t\xe1n g\u1eabu","Vui v\u1ebb, \u1ea5m \xe1p","\ud83d\ude0a")
