B.Se=s(["B\xfat c\u1ee7a t\u1edb b\u1ecb h\u1ebft m\u1ef1c. C\u1eadu cho t\u1edb m\u01b0\u1ee3n t\u1ea1m m\u1ed9t chi\u1ebfc \u0111\u01b0\u1ee3c kh\xf4ng?","Ph\u1ea7n c\xf4ng th\u1ee9c n\xe0y t\u1edb ch\u01b0a ch\xe9p k\u1ecbp. C\u1eadu ch\u1ec9 l\u1ea1i gi\xfap t\u1edb v\u1edbi.","Th\u01b0a th\u1ea7y/c\xf4, theo em ngh\u0129 l\xe0... \u1ea1.","Em xin l\u1ed7i th\u1ea7y/c\xf4 v\xec \u0111\xe3 \u0111i mu\u1ed9n. Em xin ph\xe9p v\xe0o l\u1edbp \u1ea1.","Th\u01b0a th\u1ea7y/c\xf4, em c\u1ea3m th\u1ea5y h\u01a1i m\u1ec7t. Em xin ph\xe9p xu\u1ed1ng ph\xf2ng y t\u1ebf \u1ea1.","Th\u01b0a th\u1ea7y/c\xf4, h\xecnh nh\u01b0 c\xf3 ch\xfat nh\u1ea7m l\u1eabn \u1edf \u0111i\u1ec3m s\u1ed1 c\u1ee7a em \u1ea1.","T\u1edb \u0111ang t\u1eadp trung nghe gi\u1ea3ng. L\xe1t ra ch\u01a1i ch\xfang m\xecnh n\xf3i chuy\u1ec7n ti\u1ebfp nh\xe9.","T\u1edb c\xf3 \xfd ki\u1ebfn n\xe0y cho ph\u1ea7n m\u1edf \u0111\u1ea7u c\u1ee7a nh\xf3m m\xecnh...","\xdd t\u01b0\u1edfng c\u1ee7a c\u1eadu r\u1ea5t hay, nh\u01b0ng t\u1edb s\u1ee3 nh\xf3m m\xecnh kh\xf4ng \u0111\u1ee7 th\u1eddi gian l\xe0m.","T\u1edb v\u1ebd h\u01a1i v\u1ee5ng nh\u01b0ng t\u1edb c\xf3 th\u1ec3 ph\u1ee5 tr\xe1ch ph\u1ea7n t\xecm t\xe0i li\u1ec7u v\xe0 vi\u1ebft n\u1ed9i dung.","Ch\xfac m\u1eebng c\u1eadu nh\xe9! C\u1eadu gi\u1ecfi qu\xe1.","\u0110\u1eebng bu\u1ed3n qu\xe1 c\u1eadu \u1ea1. B\xe0i sau c\u1ed1 g\u1eafng l\xe0m l\u1ea1i l\xe0 \u0111\u01b0\u1ee3c m\xe0.","T\u1edb d\xf9ng xong r\u1ed3i. C\u1ea3m \u01a1n c\u1eadu nhi\u1ec1u nh\xe9.","C\u1eadu \u01a1i, cu\u1ed1n truy\u1ec7n h\xf4m tr\u01b0\u1edbc t\u1edb cho m\u01b0\u1ee3n, c\u1eadu \u0111\u1ecdc xong ch\u01b0a cho t\u1edb xin l\u1ea1i v\u1edbi.","Em xin l\u1ed7i c\xf4 v\xec h\xf4m qua em qu\xean kh\xf4ng l\xe0m b\xe0i t\u1eadp. Em xin ph\xe9p n\u1ed9p b\xf9 v\xe0o ng\xe0y mai \u1ea1.","Ch\xe0o c\u1eadu, t\u1edb l\xe0... C\u1eadu m\u1edbi chuy\u1ec3n \u0111\u1ebfn l\u1edbp m\xecnh \u0111\xfang kh\xf4ng?","Tr\xf2 n\xe0y vui th\u1ebf. Cho t\u1edb ch\u01a1i c\xf9ng v\u1edbi \u0111\u01b0\u1ee3c kh\xf4ng?","Ra ch\u01a1i r\u1ed3i, c\u1eadu c\xf3 xu\u1ed1ng c\u0103n-tin mua \u0111\u1ed3 \u0103n g\xec kh\xf4ng? \u0110i c\xf9ng t\u1edb \u0111i.","T\u1edb c\u0169ng mu\u1ed1n \u0111i l\u1eafm nh\u01b0ng t\u1edb ph\u1ea3i \u1edf l\u1ea1i tr\u1ef1c nh\u1eadt r\u1ed3i. H\u1eb9n c\u1eadu b\u1eefa sau nh\xe9.","C\xe1i balo/\u0111\xf4i gi\xe0y n\xe0y c\u1ee7a c\u1eadu \u0111\u1eb9p th\u1ebf! C\u1eadu mua \u1edf \u0111\xe2u v\u1eady?","C\u1eadu c\xf3 sao kh\xf4ng? Nh\xecn c\u1eadu c\xf3 v\u1ebb m\u1ec7t/bu\u1ed3n.","B\u1ea1n \u01a1i, b\u1ea1n l\xe0m \u01a1n ch\u1ee5p gi\xfap t\u1ee5i m\xecnh m\u1ed9t b\u1ee9c \u1ea3nh \u1edf g\xf3c n\xe0y \u0111\u01b0\u1ee3c kh\xf4ng?","B\xe1nh n\xe0y ngon qu\xe1. C\u1ea3m \u01a1n c\u1eadu \u0111\xe3 chia cho t\u1edb nh\xe9.","C\u1eadu \u01a1i, th\xf9ng r\xe1c \u1edf ngay \u0111\u1eb1ng kia k\xeca, b\u1ecf v\xe0o \u0111\xf3 cho s\u1ea1ch tr\u01b0\u1eddng.","Ch\xe0o anh/ch\u1ecb, em mu\u1ed1n \u0111\u0103ng k\xfd v\xe0o CLB b\xf3ng r\u1ed5 c\u1ee7a tr\u01b0\u1eddng m\xecnh \u1ea1.","\xd4i t\u1edb xin l\u1ed7i! T\u1edb \u0111i v\u1ed9i qu\xe1 kh\xf4ng \u0111\u1ec3 \xfd. C\u1eadu c\xf3 sao kh\xf4ng?","C\xf3 ai v\u1eeba l\xe0m r\u01a1i c\xe1i v\xed/ch\xeca kh\xf3a \u1edf ch\u1ed7 n\xe0y kh\xf4ng \u1ea1?","D\u1ea1o n\xe0y c\u1eadu c\xf3 xem b\u1ed9 phim... kh\xf4ng? T\u1edb th\u1ea5y phim \u0111\xf3 hay l\u1eafm.","Th\u01b0a th\u1ea7y, \u0111\xe2y l\xe0 k\u1ebf ho\u1ea1ch h\u1ed9i ch\u1ee3 c\u1ee7a l\u1edbp em. Th\u1ea7y xem qua v\xe0 k\xfd duy\u1ec7t gi\xfap em v\u1edbi \u1ea1.","T\u1edb v\u1ec1 tr\u01b0\u1edbc nh\xe9. Mai g\u1eb7p l\u1ea1i!","Xin l\u1ed7i c\u1ea3 nh\xf3m, ph\u1ea7n n\u1ed9i dung c\u1ee7a t\u1edb g\u1eb7p ch\xfat tr\u1ee5c tr\u1eb7c, t\u1edb xin n\u1ed9p mu\u1ed9n v\xe0o t\u1ed1i nay nh\xe9.","Ch\xe0o c\u1eadu, t\u1edb l\xe0... h\u1ecdc c\xf9ng tr\u01b0\u1eddng v\u1edbi c\u1eadu. Th\u1ea5y c\u1eadu hay \u0111\u0103ng \u1ea3nh m\xe8o \u0111\xe1ng y\xeau qu\xe1 n\xean t\u1edb k\u1ebft b\u1ea1n.","H\xf4m nay th\u1ea5y c\u1eadu ngh\u1ec9 h\u1ecdc. C\u1eadu \u0111\u1ee1 m\u1ec7t ch\u01b0a? C\xf3 c\u1ea7n t\u1edb g\u1eedi b\xe0i ch\xe9p h\xf4m nay cho kh\xf4ng?","M\u1ecdi ng\u01b0\u1eddi \u01a1i, ai xem \u0111\u01b0\u1ee3c tin nh\u1eafn n\xe0y th\xec rep ch\u1ed1t l\u1ecbch h\u1ecdp nh\xf3m gi\xfap t\u1edb v\u1edbi nh\xe9.","Ch\xfac m\u1eebng sinh nh\u1eadt c\u1eadu nh\xe9! Ch\xfac c\u1eadu tu\u1ed5i m\u1edbi lu\xf4n vui v\u1ebb v\xe0 h\u1ecdc t\u1ed1t.","C\u1eadu \u01a1i, c\u1eadu c\xf3 file \u0111\u1ec1 c\u01b0\u01a1ng m\xf4n S\u1eed kh\xf4ng? Cho t\u1edb xin v\u1edbi.","D\u1ef1 \xe1n xong r\u1ed3i n\xean t\u1edb xin ph\xe9p r\u1eddi nh\xf3m nh\xe9. C\u1ea3m \u01a1n m\u1ecdi ng\u01b0\u1eddi nhi\u1ec1u.","L\u1edbp t\u1edb \u0111ang tham gia cu\u1ed9c thi \u1ea3nh. C\u1eadu b\u1edbt ch\xfat th\u1eddi gian nh\u1ea5n v\xe0o link th\u1ea3 tim gi\xfap l\u1edbp t\u1edb v\u1edbi nh\xe9.","H\xecnh nh\u01b0 l\u1ecbch thi c\xf3 ch\xfat thay \u0111\u1ed5i r\u1ed3i c\u1eadu \u01a1i, kh\xf4ng ph\u1ea3i ng\xe0y th\u1ee9 Hai \u0111\xe2u.","T\u1edb \u0111\u1ed3ng \xfd v\u1edbi c\xe1ch gi\u1ea3i quy\u1ebft n\xe0y c\u1ee7a c\u1eadu. R\u1ea5t h\u1ee3p l\xfd!","B\u1ed1 m\u1eb9 \u01a1i, chi\u1ec1u th\u1ee9 B\u1ea3y n\xe0y cho em \u0111i sinh nh\u1eadt b\u1ea1n Hoa \u1edf qu\xe1n tr\xe0 s\u1eefa g\u1ea7n tr\u01b0\u1eddng nh\xe9 \u1ea1.","M\u1eb9 \u0111\u1ec3 em r\u1eeda b\xe1t/lau nh\xe0 cho \u1ea1. M\u1eb9 ngh\u1ec9 ng\u01a1i \u0111i.","B\u1ed1 \u01a1i, m\xe1y t\xednh b\u1ecf t\xfai c\u1ee7a em b\u1ecb h\u1ecfng m\xe0n h\xecnh r\u1ed3i. B\u1ed1 mua gi\xfap em chi\u1ebfc m\u1edbi \u0111\u1ec3 chu\u1ea9n b\u1ecb thi h\u1ecdc k\u1ef3 nh\xe9.","Em xin l\u1ed7i b\u1ed1 m\u1eb9. Em h\u1ee9a l\u1ea7n sau s\u1ebd c\u1ea9n th\u1eadn h\u01a1n/c\u1ed1 g\u1eafng h\u1ecdc t\u1ed1t h\u01a1n.","D\u1ea1o n\xe0y em c\u1ea3m th\u1ea5y h\u01a1i m\u1ec7t v\xe0 \xe1p l\u1ef1c v\xec l\u1ecbch h\u1ecdc d\xe0y qu\xe1 b\u1ed1 m\u1eb9 \u1ea1.","Anh/Ch\u1ecb \u01a1i, l\xfac n\xe0o r\u1ea3nh ch\u1ec9 gi\xfap em c\xe2u h\u1ecfi n\xe0y v\u1edbi, em ngh\u0129 m\xe3i kh\xf4ng ra.","Th\xf4i t\u1ee5i m\xecnh kh\xf4ng c\xe3i nhau n\u1eefa. Em xem 15 ph\xfat r\u1ed3i tr\u1ea3 \u0111i\u1ec1u khi\u1ec3n cho anh nh\xe9.","Ch\xe1u ch\xe0o \xf4ng/b\xe0 \u1ea1. D\u1ea1o n\xe0y \xf4ng b\xe0 c\xf3 kh\u1ecfe kh\xf4ng \u1ea1?","Ch\xe1u c\u1ea3m \u01a1n b\xe1c \u1ea1, nh\u01b0ng ch\xe1u b\u1ecb d\u1ecb \u1ee9ng v\u1edbi t\xf4m n\xean ch\xe1u xin ph\xe9p kh\xf4ng \u0103n m\xf3n n\xe0y \u1ea1.","H\xf4m nay m\u1eb9 n\u1ea5u to\xe0n m\xf3n em th\xedch th\xf4i. Em c\u1ea3m \u01a1n m\u1eb9 nhi\u1ec1u \u1ea1."],t.s)
