B.So=s(["M\u01b0\u1ee3n \u0111\u1ed3 d\xf9ng h\u1ecdc t\u1eadp c\u1ee7a b\u1ea1n b\xean c\u1ea1nh","H\u1ecfi b\xe0i b\u1ea1n khi ch\u01b0a hi\u1ec3u l\u1eddi th\u1ea7y c\xf4","Ph\xe1t bi\u1ec3u \xfd ki\u1ebfn trong gi\u1edd h\u1ecdc","Xin ph\xe9p th\u1ea7y c\xf4 v\xe0o l\u1edbp mu\u1ed9n","Xin ph\xe9p th\u1ea7y c\xf4 ra ngo\xe0i (\u0111i v\u1ec7 sinh/xu\u1ed1ng ph\xf2ng y t\u1ebf)","\u0110\xednh ch\xednh khi th\u1ea7y c\xf4 g\u1ecdi nh\u1ea7m t\xean ho\u1eb7c ch\u1ea5m sai \u0111i\u1ec3m","Nh\u1eafc b\u1ea1n b\xean c\u1ea1nh kh\xf4ng n\xf3i chuy\u1ec7n ri\xeang","Th\u1ea3o lu\u1eadn nh\xf3m - \u0110\xf3ng g\xf3p \xfd ki\u1ebfn","Th\u1ea3o lu\u1eadn nh\xf3m - T\u1eeb ch\u1ed1i \xfd ki\u1ebfn c\u1ee7a b\u1ea1n m\u1ed9t c\xe1ch l\u1ecbch s\u1ef1","Th\u1ea3o lu\u1eadn nh\xf3m - Nh\u1eadn nhi\u1ec7m v\u1ee5 ph\xf9 h\u1ee3p v\u1edbi b\u1ea3n th\xe2n","Ch\xfac m\u1eebng b\u1ea1n \u0111\u1ea1t \u0111i\u1ec3m cao ho\u1eb7c gi\u1ea3i th\u01b0\u1edfng","An \u1ee7i b\u1ea1n khi b\u1ea1n b\u1ecb \u0111i\u1ec3m k\xe9m","Tr\u1ea3 l\u1ea1i \u0111\u1ed3 d\xf9ng h\u1ecdc t\u1eadp \u0111\xe3 m\u01b0\u1ee3n","Nh\u1eafc b\u1ea1n tr\u1ea3 l\u1ea1i \u0111\u1ed3 m\xecnh cho m\u01b0\u1ee3n","Xin l\u1ed7i th\u1ea7y c\xf4 khi qu\xean l\xe0m b\xe0i t\u1eadp v\u1ec1 nh\xe0","Ch\u1ee7 \u0111\u1ed9ng l\xe0m quen v\u1edbi m\u1ed9t b\u1ea1n m\u1edbi chuy\u1ec3n tr\u01b0\u1eddng","Xin tham gia v\xe0o m\u1ed9t nh\xf3m b\u1ea1n \u0111ang ch\u01a1i tr\xf2 ch\u01a1i (\u0111\xe1 c\u1ea7u, nh\u1ea3y d\xe2y...)","R\u1ee7 b\u1ea1n c\xf9ng \u0111i xu\u1ed1ng c\u0103n-tin","T\u1eeb ch\u1ed1i l\u1eddi r\u1ee7 \u0111i ch\u01a1i c\u1ee7a b\u1ea1n v\xec b\u1eadn vi\u1ec7c kh\xe1c","Khen ng\u1ee3i trang ph\u1ee5c/\u0111\u1ed3 d\xf9ng m\u1edbi c\u1ee7a b\u1ea1n","H\u1ecfi th\u0103m khi th\u1ea5y m\u1ed9t b\u1ea1n ng\u1ed3i bu\u1ed3n m\u1ed9t m\xecnh","Nh\u1edd b\u1ea1n ch\u1ee5p h\u1ed9 m\u1ed9t b\u1ee9c \u1ea3nh k\u1ef7 ni\u1ec7m","C\u1ea3m \u01a1n b\u1ea1n v\xec \u0111\xe3 chia s\u1ebb \u0111\u1ed3 \u0103n v\u1eb7t","Nh\u1eafc nh\u1edf b\u1ea1n v\u1ee9t r\xe1c \u0111\xfang n\u01a1i quy \u0111\u1ecbnh","\u0110\u0103ng k\xfd tham gia m\u1ed9t c\xe2u l\u1ea1c b\u1ed9 (CLB) tr\u01b0\u1eddng","Xin l\u1ed7i v\xec v\xf4 t\xecnh \u0111\u1ee5ng tr\xfang b\u1ea1n h\xe0nh lang","Nh\u1eb7t \u0111\u01b0\u1ee3c \u0111\u1ed3 r\u01a1i v\xe0 t\xecm ng\u01b0\u1eddi tr\u1ea3 l\u1ea1i","Chia s\u1ebb v\u1ec1 s\u1edf th\xedch c\xe1 nh\xe2n (phim \u1ea3nh, \xe2m nh\u1ea1c, game)","Xin ch\u1eef k\xfd ho\u1eb7c \xfd ki\u1ebfn c\u1ee7a th\u1ea7y c\xf4 cho ho\u1ea1t \u0111\u1ed9ng \u0110o\xe0n/\u0110\u1ed9i","Ch\xe0o t\u1ea1m bi\u1ec7t b\u1ea1n b\xe8 khi tan h\u1ecdc","Nh\u1eafn tin xin ph\xe9p tr\u01b0\u1edfng nh\xf3m n\u1ed9p mu\u1ed9n ph\u1ea7n vi\u1ec7c \u0111\u01b0\u1ee3c giao","K\u1ebft b\u1ea1n v\xe0 g\u1eedi l\u1eddi ch\xe0o \u0111\u1ea7u ti\xean tr\xean m\u1ea1ng x\xe3 h\u1ed9i","H\u1ecfi han t\xecnh h\xecnh s\u1ee9c kh\u1ecfe c\u1ee7a b\u1ea1n qua tin nh\u1eafn khi b\u1ea1n ngh\u1ec9 h\u1ecdc","Nh\u1eafc nh\u1edf th\xe0nh vi\xean nh\xf3m ph\u1ea3n h\u1ed3i tin nh\u1eafn c\xf4ng vi\u1ec7c","Ch\xfac m\u1eebng sinh nh\u1eadt b\u1ea1n qua m\u1ea1ng x\xe3 h\u1ed9i","H\u1ecfi m\u01b0\u1ee3n t\xe0i li\u1ec7u, file \u0111\u1ec1 c\u01b0\u01a1ng \xf4n t\u1eadp","R\u1eddi kh\u1ecfi m\u1ed9t nh\xf3m chat kh\xf4ng c\xf2n ho\u1ea1t \u0111\u1ed9ng ho\u1eb7c kh\xf4ng li\xean quan","Nh\u1edd b\u1ea1n b\xecnh ch\u1ecdn (vote) cho b\xe0i d\u1ef1 thi c\u1ee7a l\u1edbp/c\xe1 nh\xe2n","\u0110\xednh ch\xednh th\xf4ng tin sai l\u1ec7ch trong nh\xf3m chat","B\xe0y t\u1ecf s\u1ef1 \u0111\u1ed3ng t\xecnh/\u1ee7ng h\u1ed9 m\u1ed9t \xfd ki\u1ebfn trong group b\xe0i t\u1eadp","Xin ph\xe9p b\u1ed1 m\u1eb9 \u0111i ch\u01a1i v\u1edbi b\u1ea1n b\xe8 v\xe0o cu\u1ed1i tu\u1ea7n","Ch\u1ee7 \u0111\u1ed9ng \u0111\u1ec1 xu\u1ea5t gi\xfap \u0111\u1ee1 b\u1ed1 m\u1eb9 vi\u1ec7c nh\xe0","Th\u1ea3o lu\u1eadn v\u1edbi b\u1ed1 m\u1eb9 v\u1ec1 vi\u1ec7c mua \u0111\u1ed3 d\xf9ng h\u1ecdc t\u1eadp m\u1edbi (m\xe1y t\xednh, s\xe1ch v\u1edf)","Xin l\u1ed7i b\u1ed1 m\u1eb9 khi l\u1ee1 l\xe0m h\u1ecfng \u0111\u1ed3 \u0111\u1ea1c trong nh\xe0 ho\u1eb7c b\u1ecb \u0111i\u1ec3m k\xe9m","T\xe2m s\u1ef1 v\u1edbi b\u1ed1 m\u1eb9 v\u1ec1 \xe1p l\u1ef1c h\u1ecdc t\u1eadp ho\u1eb7c kh\xf3 kh\u0103n \u1edf tr\u01b0\u1eddng","Nh\u1edd anh/ch\u1ecb/em trong nh\xe0 gi\u1ea3ng h\u1ed9 b\xe0i t\u1eadp kh\xf3","H\xf2a gi\u1ea3i m\xe2u thu\u1eabn nh\u1ecf v\u1edbi anh/ch\u1ecb/em (tranh gi\xe0nh \u0111\u1ed3, tivi...)","G\u1ecdi \u0111i\u1ec7n h\u1ecfi th\u0103m \xf4ng b\xe0/ng\u01b0\u1eddi th\xe2n \u1edf xa","T\u1eeb ch\u1ed1i l\u1eddi m\u1eddi \u0103n m\xf3n m\xecnh b\u1ecb d\u1ecb \u1ee9ng khi \u0111i \u0103n nh\xe0 h\u1ecd h\xe0ng","C\u1ea3m \u01a1n b\u1ed1 m\u1eb9 v\xec m\u1ed9t m\xf3n qu\xe0 ho\u1eb7c m\u1ed9t b\u1eefa \u0103n ngon"],t.s)
