B.YO=new A.iB("Th\u1edf b\u1ee5ng","Gi\u1ea3m c\u0103ng \u2014 d\u1ec5 ng\u1ee7","https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=800&h=600&fit=crop","https://www.youtube.com/results?search_query=diaphragmatic+breathing+vietnamese","### Th\u1edf b\u1eb1ng b\u1ee5ng\n1. Ng\u1ed3i th\u1eb3ng ho\u1eb7c n\u1eb1m ng\u1eeda, m\u1ed9t tay tr\xean ng\u1ef1c \u2014 m\u1ed9t tay tr\xean b\u1ee5ng.\n2. H\xedt v\xe0o m\u0169i: b\u1ee5ng ph\xecnh, ng\u1ef1c \xedt nh\xedch.\n3. Th\u1edf ra ch\u1eadm: b\u1ee5ng h\xf3p.\n4. L\u1eb7p 5\u201310 chu k\u1ef3.\n\n**G\u1ee3i \xfd:** nh\u1eafm m\u1eaft n\u1ebfu d\u1ec5 t\u1eadp trung h\u01a1n.\n",null)
B.YL=new A.iB("Th\u1edf lu\xe2n phi\xean","C\xe2n b\u1eb1ng \u2014 gi\u1ea3m lo","https://images.unsplash.com/photo-1599447421405-0c1a9f8be6a7?w=800&h=600&fit=crop","https://www.youtube.com/results?search_query=nadi+shodhana+pranayama","### Th\u1edf lu\xe2n phi\xean (Nadi Shodhana)\n1. Ng\u1ed3i th\u1eb3ng. Tay ph\u1ea3i: ng\xf3n c\xe1i b\u1ecbt m\u0169i ph\u1ea3i \u2014 h\xedt v\xe0o tr\xe1i.\n2. B\u1ecbt tr\xe1i, m\u1edf ph\u1ea3i \u2014 th\u1edf ra ph\u1ea3i.\n3. H\xedt ph\u1ea3i \u2014 \u0111\u1ed5i b\xean, th\u1edf ra tr\xe1i. L\u1eb7p \u0111\u1ec1u 2\u20133 ph\xfat.\n",null)
B.YS=new A.iB("Th\u1edf ong k\xeau","D\u1ecbu th\u1ea7n kinh","https://images.unsplash.com/photo-1599901860904-17e6ed7083a0?w=800&h=600&fit=crop","https://www.youtube.com/results?search_query=bhramari+pranayama","### Th\u1edf ong k\xeau (Bhramari)\n1. Ng\u1ed3i v\u1eaft ch\xe9o ch\xe2n, l\u01b0ng th\u1eb3ng, nh\u1eafm m\u1eaft.\n2. B\u1ecbt tai nh\u1eb9 b\u1eb1ng ng\xf3n c\xe1i, h\xedt s\xe2u.\n3. Th\u1edf ra t\u1ea1o ti\u1ebfng \xf9 nh\u1eb9 trong c\u1ed5 h\u1ecdng (nh\u01b0 ong).\n4. L\u1eb7p 5\u20138 l\u1ea7n.\n",null)
B.YU=new A.iB("Nh\u1ea1c kh\xf4ng l\u1eddi th\u01b0 gi\xe3n","Thi\u1ec1n ng\u1eafn \u2014 5 ph\xfat","https://images.unsplash.com/photo-1518709268805-4e9042af2176?w=800&h=600&fit=crop","https://www.youtube.com/results?search_query=ambient+meditation+no+lyrics","### Nghe nh\u1eb9 + th\u1edf theo nh\u1ecbp\n1. \u0110eo tai nghe v\u1eeba ph\u1ea3i \xe2m l\u01b0\u1ee3ng.\n2. H\xedt 4 nh\u1ecbp \u2014 gi\u1eef 2 \u2014 th\u1edf 6 (n\u1ebfu kh\xf3 th\xec ch\u1ec9 c\u1ea7n th\u1edf ra d\xe0i h\u01a1n h\xedt).\n3. Khi t\xe2m tr\xf4i, ghi nh\u1eadn v\xe0 quay l\u1ea1i h\u01a1i th\u1edf.\n","assets/audio/relaxation_music.mp3")
B.YT=new A.iB("Piano / lo-fi t\u1eadp trung","L\xe0m vi\u1ec7c nh\u1eb9 \u2014 kh\xf4ng xao nh\xe3ng","https://images.unsplash.com/photo-1493225457124-a3eb161ffa5f?w=800&h=600&fit=crop","https://www.youtube.com/results?search_query=lofi+piano+relax","### C\xe1ch d\xf9ng\n1. Ch\u1ecdn m\u1ed9t playlist 45\u201360 ph\xfat.\n2. \u1ea4n play, \u0111\u1eb7t \u0111i\u1ec7n tho\u1ea1i xa t\u1ea7m m\u1eaft.\n3. M\u1ed7i 25 ph\xfat \u0111\u1ee9ng d\u1eady du\u1ed7i vai 1 ph\xfat.\n","assets/audio/lofi_piano.mp3")
B.YR=new A.iB("T\u01b0 th\u1ebf \u0111\u1ee9a tr\u1ebb","Balasana","https://images.unsplash.com/photo-1552196563-55cd4e45efb3?w=800&h=600&fit=crop","https://www.youtube.com/results?search_query=child+pose+yoga+tutorial","### C\xe1ch l\xe0m\n1. Qu\u1ef3, g\u1ed1i r\u1ed9ng b\u1eb1ng h\xf4ng, ng\u1ed3i tr\xean g\xf3t (n\u1ebfu \u0111\u01b0\u1ee3c).\n2. G\u1eadp ng\u01b0\u1eddi v\u1ec1 ph\xeda tr\u01b0\u1edbc, tay du\u1ed7i d\xe0i, tr\xe1n ch\u1ea1m g\u1ed1i ho\u1eb7c th\u1ea3m.\n3. Gi\u1eef 5\u201310 nh\u1ecbp th\u1edf ch\u1eadm.\n",null)
B.YK=new A.iB("M\xe8o \u2014 b\xf2","Cat\u2013Cow","https://images.unsplash.com/photo-1506629905607-0b5ab9a9e21a?w=800&h=600&fit=crop","https://www.youtube.com/results?search_query=cat+cow+yoga","### C\xe1ch l\xe0m\n1. B\u1ed1n ch\xe2n: tay d\u01b0\u1edbi vai, g\u1ed1i d\u01b0\u1edbi h\xf4ng.\n2. H\xedt: v\xf5ng l\u01b0ng, ng\u1ea9ng nh\u1eb9 \u0111\u1ea7u (b\xf2).\n3. Th\u1edf: cong l\u01b0ng, c\u1eb1m v\xe0o ng\u1ef1c (m\xe8o).\n4. L\u1eb7p 8\u201312 chu k\u1ef3.\n",null)
B.YQ=new A.iB("G\xe1c ch\xe2n l\xean t\u01b0\u1eddng","Legs up the wall","https://images.unsplash.com/photo-1518611012118-696072aa579a?w=800&h=600&fit=crop","https://www.youtube.com/results?search_query=legs+up+the+wall+yoga","### C\xe1ch l\xe0m\n1. N\u1eb1m s\xe1t t\u01b0\u1eddng, \u0111\u01b0a ch\xe2n d\u1ecdc t\u01b0\u1eddng l\xean tr\u1eddi.\n2. Tay \u0111\u1ec3 b\xean h\xf4ng ho\u1eb7c tr\xean b\u1ee5ng.\n3. Gi\u1eef 5\u201310 ph\xfat, th\u1edf \u0111\u1ec1u.\n",null)
B.YP=new A.iB("C\xe1nh b\u01b0\u1edbm","Butterfly","https://images.unsplash.com/photo-1545389336-cf090694435e?w=800&h=600&fit=crop","https://www.youtube.com/results?search_query=butterfly+pose+yoga","### C\xe1ch l\xe0m\n1. Ng\u1ed3i, l\xf2ng b\xe0n ch\xe2n ch\u1ea1m nhau, \u0111\u1ea7u g\u1ed1i m\u1edf hai b\xean.\n2. L\u01b0ng th\u1eb3ng, c\xf3 th\u1ec3 nh\u1ea5n nh\u1eb9 \u0111\u1ea7u g\u1ed1i xu\u1ed1ng.\n3. Gi\u1eef 8\u201310 nh\u1ecbp th\u1edf.\n",null)
B.YN=new A.iB("Savasana","Th\u01b0 gi\xe3n s\xe2u","https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=800&h=600&fit=crop","https://www.youtube.com/results?search_query=savasana+guided+relaxation","### C\xe1ch l\xe0m\n1. N\u1eb1m ng\u1eeda, ch\xe2n tay bu\xf4ng t\u1ef1 nhi\xean, l\xf2ng b\xe0n tay ng\u1eeda.\n2. Nh\u1eafm m\u1eaft, th\u1ea3 l\u1ecfng h\xe0m.\n3. Theo d\xf5i h\u01a1i th\u1edf 3\u20135 ph\xfat.\n",null)
